type ParseQuery<S extends string> = S extends "" 
  ? {} 
  : S extends `${infer Key}=${infer Value}&${infer Rest}`
    ? { [Key extends string]: Value } & ParseQuery<Rest>
    : S extends `${infer Key}=${infer Value}`
      ? { [Key extends string]: Value }
      : {};

export type ParseQueryType<S extends string> = ParseQuery<S>;

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private handlers: Record<string, Array<(...args: unknown[]) => void>> = {};

  on<K extends keyof TEvents>(
    name: K,
    handler: (...args: TEvents[K]) => void
  ): void {
    if (!this.handlers[name]) {
      this.handlers[name] = [];
    }
    this.handlers[name]!.push(handler);
  }

  emit<K extends keyof TEvents>(
    name: K,
    ...args: TEvents[K]
  ): void {
    const eventHandlers = this.handlers[name];
    if (eventHandlers) {
      for (const handler of eventHandlers) {
        handler(...args);
      }
    }
  }
}

export class MedianStream {
  private lowHeap: number[] = [];
  private highHeap: number[] = [];

  /**
   * Adds a number to the stream and maintains two heaps:
   * 1. lowHeap (Max-Heap): Stores the smaller half of numbers.
   * 2. highHeap (Min-Heap): Stores the larger half of numbers.
   * 
   * Time Complexity: O(log n) per add.
   */
  add(n: number): void {
    if (this.lowHeap.length === 0 || n <= this.lowHeap[0]) {
      this.lowHeap.push(n);
      this.bubbleUp(this.lowHeap, this.lowHeap.length - 1);
    } else {
      this.highHeap.push(n);
      this.bubbleUp(this.highHeap, this.highHeap.length - 1);
    }

    // Rebalance heaps so size difference is at most 1
    if (this.lowHeap.length > this.highHeap.length + 1) {
      const val = this.extractMax(this.lowHeap);
      this.highHeap.push(val);
      this.bubbleUp(this.highHeap, this.highHeap.length - 1);
    } else if (this.highHeap.length > this.lowHeap.length) {
      const val = this.extractMin(this.highHeap);
      this.lowHeap.push(val);
      this.bubbleUp(this.lowHeap, this.lowHeap.length - 1);
    }
  }

  /**
   * Returns the current median.
   * Time Complexity: O(1).
   */
  median(): number {
    if (this.lowHeap.length === 0 && this.highHeap.length === 0) {
      throw new Error("No numbers added to stream.");
    }

    if (this.lowHeap.length > this.highHeap.length) {
      return this.lowHeap[0];
    } else if (this.highHeap.length > this.lowHeap.length) {
      return this.highHeap[0];
    } else {
      return (this.lowHeap[0] + this.highHeap[0]) / 2;
    }
  }

  private bubbleUp(heap: number[], index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      const isLowHeap = heap === this.lowHeap;

      // For lowHeap (Max-Heap), parent must be >= child
      // For highHeap (Min-Heap), parent must be <= child
      const shouldSwap = isLowHeap 
        ? heap[index] > heap[parentIndex] 
        : heap[index] < heap[parentIndex];

      if (!shouldSwap) break;

      [heap[index], heap[parentIndex]] = [heap[parentIndex], heap[index]];
      index = parentIndex;
    }
  }

  private sinkDown(heap: number[], index: number): void {
    const length = heap.length;
    while (true) {
      let targetIndex = index;
      const leftChild = 2 * index + 1;
      const rightChild = 2 * index + 2;
      const isLowHeap = heap === this.lowHeap;

      if (leftChild < length) {
        const shouldSwapLeft = isLowHeap 
          ? heap[leftChild] > heap[targetIndex] 
          : heap[leftChild] < heap[targetIndex];
        if (shouldSwapLeft) targetIndex = leftChild;
      }

      if (rightChild < length) {
        const shouldSwapRight = isLowHeap 
          ? heap[rightChild] > heap[targetIndex] 
          : heap[rightChild] < heap[targetIndex];
        if (shouldSwapRight) targetIndex = rightChild;
      }

      if (targetIndex === index) break;

      [heap[index], heap[targetIndex]] = [heap[targetIndex], heap[index]];
      index = targetIndex;
    }
  }

  private extractMax(heap: number[]): number {
    const max = heap[0];
    const last = heap.pop()!;
    if (heap.length > 0) {
      heap[0] = last;
      this.sinkDown(heap, 0);
    }
    return max;
  }

  private extractMin(heap: number[]): number {
    const min = heap[0];
    const last = heap.pop()!;
    if (heap.length > 0) {
      heap[0] = last;
      this.sinkDown(heap, 0);
    }
    return min;
  }
}
